import { useEffect, useRef, useState } from 'react'
import { BarcodeDetector as PonyfillBarcodeDetector, prepareZXingModule } from 'barcode-detector/ponyfill'
import zxingReaderWasmUrl from 'zxing-wasm/reader/zxing_reader.wasm?url'
import { Button } from './ui/Button'
import { StatusNote } from './ui/StatusNote'

// Camera scanning for Barcode #2 (§2.2: Code128, generated by
// barcodeLabel.ts/Barcode2Display.tsx). Self-contained: owns its own
// open/closed state, mounts the camera only while open, and calls
// `onDecode` with the raw decoded string for every successful read — the
// CALLER is responsible for feeding that string into the exact same
// handler the manual input already uses (see OmborChiqimTab.tsx's
// `processBarcode`), so a camera read behaves identically to typing the
// same code, including a voided/claimed/wrong-stage barcode failing
// exactly the same way.
//
// 🔒 Replaces html5-qrcode — confirmed on real hardware to open the
// camera but never decode a real printed CODE_128 label, even with a
// resolution hint (DECISIONS.md "Camera scanner" entries). Uses the
// native BarcodeDetector where the browser has it (Chrome/Samsung
// Internet on Android — hardware-accelerated, meaningfully stronger on
// 1D), and falls back to the `barcode-detector` ponyfill (ZXing-C++
// wasm) everywhere else — desktop browsers, iOS Safari, Firefox — none
// of which implement BarcodeDetector natively. Both share the identical
// `detect(video)` shape, so the scan loop below never needs to know
// which one it's holding.
//
// The ponyfill's wasm defaults to fetching from a CDN at runtime, which
// would break this app's "works offline once cached" requirement
// (PHASE0.md Part E) — prepareZXingModule below points it at the copy
// Vite bundles into this build instead (also added to vite.config.ts's
// PWA `globPatterns` so the service worker actually precaches it).
prepareZXingModule({
  overrides: {
    locateFile: (path: string) => (path.endsWith('.wasm') ? zxingReaderWasmUrl : path),
  },
})

interface Detector {
  detect(image: HTMLVideoElement): Promise<Array<{ rawValue: string }>>
}

function createDetector(): Detector {
  const native = (window as unknown as { BarcodeDetector?: new (opts: { formats: string[] }) => Detector }).BarcodeDetector
  const Ctor = native ?? PonyfillBarcodeDetector
  return new Ctor({ formats: ['code_128'] })
}

const SCAN_INTERVAL_MS = 100 // ~10fps — matches the previous html5-qrcode `fps: 10`

export function BarcodeCameraScanner({ onDecode }: { onDecode: (code: string) => void }) {
  const [open, setOpen] = useState(false)
  const [cameraError, setCameraError] = useState<string | null>(null)
  const videoRef = useRef<HTMLVideoElement | null>(null)
  const lastCodeRef = useRef<{ code: string; at: number } | null>(null)
  const onDecodeRef = useRef(onDecode)
  onDecodeRef.current = onDecode

  useEffect(() => {
    if (!open) return
    let cancelled = false
    let stream: MediaStream | null = null
    let videoEl: HTMLVideoElement | null = null
    let timeoutId: number | null = null
    setCameraError(null)

    const detector = createDetector()

    navigator.mediaDevices
      .getUserMedia({
        video: {
          facingMode: 'environment',
          width: { ideal: 1280 },
          height: { ideal: 720 },
        },
        audio: false,
      })
      .then((mediaStream) => {
        if (cancelled) {
          mediaStream.getTracks().forEach((track) => track.stop())
          return
        }
        stream = mediaStream
        videoEl = videoRef.current
        if (!videoEl) return
        videoEl.srcObject = mediaStream
        videoEl.play().catch(() => {})

        const scanLoop = async () => {
          if (cancelled) return
          const currentVideo = videoRef.current
          if (currentVideo && currentVideo.readyState >= currentVideo.HAVE_CURRENT_DATA) {
            try {
              const results = await detector.detect(currentVideo)
              const decodedText = results[0]?.rawValue
              if (decodedText) {
                const now = Date.now()
                const last = lastCodeRef.current
                if (!last || last.code !== decodedText || now - last.at >= 1500) {
                  lastCodeRef.current = { code: decodedText, at: now }
                  onDecodeRef.current(decodedText)
                }
              }
            } catch {
              // No code in this frame, or a transient decode error —
              // expected noise, same as html5-qrcode's per-frame callback.
            }
          }
          if (!cancelled) timeoutId = window.setTimeout(scanLoop, SCAN_INTERVAL_MS)
        }
        scanLoop()
      })
      .catch(() => {
        if (cancelled) return
        setCameraError(
          'Kameraga ruxsat berilmadi yoki kamera topilmadi. Pastdagi maydonga qo\'lda kiriting yoki skaner qurilmasidan foydalaning.',
        )
      })

    return () => {
      cancelled = true
      if (timeoutId !== null) window.clearTimeout(timeoutId)
      stream?.getTracks().forEach((track) => track.stop())
      if (videoEl) videoEl.srcObject = null
    }
  }, [open])

  if (!open) {
    return (
      <Button variant="primary" size="lg" fullWidth onClick={() => setOpen(true)}>
        📷 Kamerani yoqish
      </Button>
    )
  }

  return (
    <div className="space-y-2 rounded-md border border-slate-300 bg-slate-900 p-2 dark:border-slate-700">
      <video ref={videoRef} className="mx-auto max-w-xs overflow-hidden rounded-md" autoPlay muted playsInline />
      {cameraError && (
        <div className="rounded-md bg-white p-2 dark:bg-slate-800">
          <StatusNote tone="problem">{cameraError}</StatusNote>
        </div>
      )}
      <Button variant="secondary" size="md" fullWidth onClick={() => setOpen(false)} className="bg-white dark:bg-slate-800">
        Kamerani yopish
      </Button>
    </div>
  )
}
